// HeapSortViaExtract builds a min-heap and extracts all elements in sorted order.
func HeapSortViaExtract(arr []int) []int {
	heap := make([]int, 0, len(arr))

	siftUp := func(i int) {
		for i > 0 {
			parent := (i - 1) / 2
			if heap[i] < heap[parent] {
				heap[i], heap[parent] = heap[parent], heap[i]
				i = parent
			} else {
				break
			}
		}
	}

	siftDown := func(i, size int) {
		for {
			smallest := i
			left, right := 2*i+1, 2*i+2
			if left < size && heap[left] < heap[smallest] {
				smallest = left
			}
			if right < size && heap[right] < heap[smallest] {
				smallest = right
			}
			if smallest != i {
				heap[i], heap[smallest] = heap[smallest], heap[i]
				i = smallest
			} else {
				break
			}
		}
	}

	for _, val := range arr {
		heap = append(heap, val)
		siftUp(len(heap) - 1)
	}

	result := make([]int, 0, len(arr))
	for len(heap) > 0 {
		result = append(result, heap[0])
		heap[0] = heap[len(heap)-1]
		heap = heap[:len(heap)-1]
		if len(heap) > 0 {
			siftDown(0, len(heap))
		}
	}

	return result
}

public class HeapOperations {

    public static int[] heapSortViaExtract(int[] arr) {
        int n = arr.length;
        if (n == 0) return new int[0];

        int[] heap = new int[n];
        int size = 0;

        for (int val : arr) {
            heap[size] = val;
            int i = size;
            size++;
            while (i > 0) {
                int parent = (i - 1) / 2;
                if (heap[i] < heap[parent]) {
                    int temp = heap[i]; heap[i] = heap[parent]; heap[parent] = temp;
                    i = parent;
                } else break;
            }
        }

        int[] result = new int[n];
        for (int r = 0; r < n; r++) {
            result[r] = heap[0];
            size--;
            heap[0] = heap[size];
            int i = 0;
            while (true) {
                int smallest = i;
                int left = 2 * i + 1, right = 2 * i + 2;
                if (left < size && heap[left] < heap[smallest]) smallest = left;
                if (right < size && heap[right] < heap[smallest]) smallest = right;
                if (smallest != i) {
                    int temp = heap[i]; heap[i] = heap[smallest]; heap[smallest] = temp;
                    i = smallest;
                } else break;
            }
        }
        return result;
    }
}

fun heapSortViaExtract(arr: IntArray): IntArray {
    val heap = mutableListOf<Int>()

    fun siftUp(idx: Int) {
        var i = idx
        while (i > 0) {
            val parent = (i - 1) / 2
            if (heap[i] < heap[parent]) {
                val tmp = heap[i]; heap[i] = heap[parent]; heap[parent] = tmp
                i = parent
            } else break
        }
    }

    fun siftDown(idx: Int, size: Int) {
        var i = idx
        while (true) {
            var smallest = i
            val left = 2 * i + 1; val right = 2 * i + 2
            if (left < size && heap[left] < heap[smallest]) smallest = left
            if (right < size && heap[right] < heap[smallest]) smallest = right
            if (smallest != i) {
                val tmp = heap[i]; heap[i] = heap[smallest]; heap[smallest] = tmp
                i = smallest
            } else break
        }
    }

    for (v in arr) {
        heap.add(v)
        siftUp(heap.size - 1)
    }

    val result = mutableListOf<Int>()
    while (heap.isNotEmpty()) {
        result.add(heap[0])
        heap[0] = heap[heap.size - 1]
        heap.removeAt(heap.size - 1)
        if (heap.isNotEmpty()) siftDown(0, heap.size)
    }
    return result.toIntArray()
}

