pub fn heap_sort_via_extract(arr: &[i32]) -> Vec<i32> {
    let mut heap: Vec<i32> = Vec::new();

    fn sift_up(heap: &mut Vec<i32>, mut i: usize) {
        while i > 0 {
            let parent = (i - 1) / 2;
            if heap[i] < heap[parent] {
                heap.swap(i, parent);
                i = parent;
            } else {
                break;
            }
        }
    }

    fn sift_down(heap: &mut Vec<i32>, mut i: usize, size: usize) {
        loop {
            let mut smallest = i;
            let left = 2 * i + 1;
            let right = 2 * i + 2;
            if left < size && heap[left] < heap[smallest] { smallest = left; }
            if right < size && heap[right] < heap[smallest] { smallest = right; }
            if smallest != i {
                heap.swap(i, smallest);
                i = smallest;
            } else {
                break;
            }
        }
    }

    for &val in arr {
        heap.push(val);
        sift_up(&mut heap, heap.len() - 1);
    }

    let mut result = Vec::new();
    while !heap.is_empty() {
        result.push(heap[0]);
        let last = heap.len() - 1;
        heap[0] = heap[last];
        heap.pop();
        if !heap.is_empty() {
            sift_down(&mut heap, 0, heap.len());
        }
    }

    result
}

object HeapOperations {

  def heapSortViaExtract(arr: Array[Int]): Array[Int] = {
    val heap = scala.collection.mutable.ArrayBuffer[Int]()

    def siftUp(idx: Int): Unit = {
      var i = idx
      while (i > 0) {
        val parent = (i - 1) / 2
        if (heap(i) < heap(parent)) {
          val tmp = heap(i); heap(i) = heap(parent); heap(parent) = tmp
          i = parent
        } else return
      }
    }

    def siftDown(idx: Int, size: Int): Unit = {
      var i = idx
      var continue_ = true
      while (continue_) {
        var smallest = i
        val left = 2 * i + 1; val right = 2 * i + 2
        if (left < size && heap(left) < heap(smallest)) smallest = left
        if (right < size && heap(right) < heap(smallest)) smallest = right
        if (smallest != i) {
          val tmp = heap(i); heap(i) = heap(smallest); heap(smallest) = tmp
          i = smallest
        } else continue_ = false
      }
    }

    for (v <- arr) {
      heap += v
      siftUp(heap.size - 1)
    }

    val result = scala.collection.mutable.ArrayBuffer[Int]()
    while (heap.nonEmpty) {
      result += heap(0)
      heap(0) = heap(heap.size - 1)
      heap.remove(heap.size - 1)
      if (heap.nonEmpty) siftDown(0, heap.size)
    }
    result.toArray
  }
}

